    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Sport Balance - 4w 3x/wk',
    'balance',
    3,
    60,
    ARRAY['Improve athletic performance', 'Develop explosiveness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Sport Balance'
ON CONFLICT DO NOTHING;

